const h=document.documentElement;try{if(localStorage.getItem('theme')==='dark')h.classList.add('dark');}catch(e){}
const tb=document.getElementById('thm');if(tb){tb.addEventListener('click',function(){h.classList.toggle('dark');try{localStorage.setItem('theme',h.classList.contains('dark')?'dark':'light');}catch(e){}});}
const nv=document.getElementById('nav');if(nv){window.addEventListener('scroll',()=>nv.classList.toggle('scrolled',scrollY>40));}
const hm=document.getElementById('ham'),mx=document.getElementById('mobx'),mb=document.getElementById('mob');
if(hm&&mb)hm.onclick=()=>mb.classList.add('open');if(mx&&mb)mx.onclick=()=>mb.classList.remove('open');
if(mb){document.querySelectorAll('.ml').forEach(l=>l.onclick=()=>mb.classList.remove('open'));}
const ob=new IntersectionObserver(es=>{es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('vis');ob.unobserve(e.target);}});},{threshold:0.08,rootMargin:'0px 0px -30px 0px'});
document.querySelectorAll('.rv').forEach(el=>ob.observe(el));
document.querySelectorAll('a[href^="#"]').forEach(a=>{a.addEventListener('click',e=>{e.preventDefault();const t=document.querySelector(a.getAttribute('href'));if(t)t.scrollIntoView({behavior:'smooth',block:'start'});});});
